// Filtra mensagens de grupos e normaliza o payload Evolution
const body = $input.first().json.body || $input.first().json;

// Aceita events: messages.upsert ou messages.update
const event = body.event || '';
if (!['messages.upsert', 'messages.update', 'message'].includes(event)) {
  return [];
}

const rawMessages = body.data?.messages || (Array.isArray(body.data) ? body.data : []);

// Team member JIDs — adicione os JIDs da equipe CASE aqui
// Formato: 55DDDNNNNNNNNN@s.whatsapp.net
const TEAM_JIDS = ($env.TEAM_MEMBER_JIDS || '').split(',').map(s => s.trim()).filter(Boolean);

const results = [];

for (const msg of rawMessages) {
  const remoteJid = msg.key?.remoteJid || '';

  // Apenas grupos
  if (!remoteJid.endsWith('@g.us')) continue;

  // Ignora mensagens próprias do bot
  if (msg.key?.fromMe) continue;

  // Precisa de message_id
  const messageId = msg.key?.id;
  if (!messageId) continue;

  // Tipo e conteúdo da mensagem
  let contentType = 'other';
  let contentText = null;

  if (msg.message?.conversation) {
    contentType = 'text';
    contentText = msg.message.conversation;
  } else if (msg.message?.extendedTextMessage?.text) {
    contentType = 'text';
    contentText = msg.message.extendedTextMessage.text;
  } else if (msg.message?.audioMessage) {
    contentType = 'audio';
  } else if (msg.message?.imageMessage) {
    contentType = 'image';
    contentText = msg.message.imageMessage.caption || null;
  } else if (msg.message?.videoMessage) {
    contentType = 'video';
    contentText = msg.message.videoMessage.caption || null;
  } else if (msg.message?.documentMessage) {
    contentType = 'document';
    contentText = msg.message.documentMessage.fileName || null;
  } else if (msg.message?.reactionMessage) {
    contentType = 'reaction';
    contentText = msg.message.reactionMessage.text || null;
  } else if (msg.message?.stickerMessage) {
    contentType = 'sticker';
  }

  const senderJid = msg.participant || msg.key?.participant || '';
  const isFromTeam = TEAM_JIDS.length > 0 && TEAM_JIDS.includes(senderJid);

  const timestamp = msg.messageTimestamp
    ? new Date(Number(msg.messageTimestamp) * 1000).toISOString()
    : new Date().toISOString();

  results.push({
    json: {
      // Campos para wa_message_queue
      message_id: messageId,
      group_jid:  remoteJid,
      status:     'pending',
      payload: {
        sender_jid:   senderJid,
        sender_name:  msg.pushName || null,
        is_from_team: isFromTeam,
        content_type: contentType,
        content_text: contentText,
        timestamp,
        raw:          msg
      }
    }
  });
}

return results;
